from collections import defaultdict

def solve(nums: list[int], k: int, m: int) -> int:
    def is_valid(freq: dict) -> bool:
        for count in freq.values():
            if count < m:
                return False
        return True

    count = 0
    n = len(nums)
    freq = defaultdict(int)
    left = 0

    for right in range(n):
        freq[nums[right]] += 1

        while len(freq) > k:
            freq[nums[left]] -= 1
            if freq[nums[left]] == 0:
                del freq[nums[left]]
            left += 1

        if len(freq) == k and is_valid(freq):
            count += 1

    return count
